mapper.sql:
H.CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
AND H.DEPTNO = D.DEPTNO(+)
AND HP.PERSON_ID = H.PERSON_ID
AND H.EMPID NOT LIKE '111111%'
AND EXISTS (
    SELECT B1.DEPTID
    FROM HR_DEPARTMENT B1
    WHERE B1.DEPTNO = D.DEPTNO
    START WITH B1.DEPTNO IN (
        SELECT HRD.DEPTID
        FROM HR_DEPARTMENT HRD
        WHERE HRD.MANAGER_EMP_ID = #{adminID, jdbcType=VARCHAR}
    )
    CONNECT BY PRIOR B1.DEPTNO = B1.PARENT_DEPT_NO
    UNION
    SELECT ASI.DEPTNO
    FROM AR_SUPERVISOR_INFO ASI
    WHERE ASI.DEPTNO = D.DEPTNO
      AND ASI.PERSON_ID = #{adminID, jdbcType=VARCHAR}
)


        AND H.EMP_OFFICE = #{empOffice, jdbcType=VARCHAR}


        AND H.EMP_OFFICE = '15119'



    AND (
        UPPER(H.EMPID) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%'
        OR CONVERTTOUNSIGN(UPPER(H.LOCAL_NAME)) LIKE '%' || CONVERTTOUNSIGN(UPPER(#{keyword, jdbcType=VARCHAR})) || '%'
    )


    AND INSTR(',' || #{deptNos, jdbcType=VARCHAR} || ',', ',' || H.DEPTNO || ',') > 0


    AND H.POST_FAMILY = #{postFamily, jdbcType=VARCHAR}


    AND H.EMP_TYPE_CODE = #{empTypeCode, jdbcType=VARCHAR}
